            be_dofunc(vm, top, 3); /* call method 'member' */
            vm->top -= 4;
            return var_tobool(top);
        }
    }
    return bfalse;
}

bbool be_class_setmember(bvm *vm, bclass *o, bstring *name, bvalue *src)
